import anthropic
import json
from pydantic import BaseModel, Field
from typing import Literal

# 1. Define the schema with Pydantic
class SentimentResult(BaseModel):
    sentiment: Literal["positive", "negative", "neutral", "mixed"]
    confidence: float = Field(ge=0.0, le=1.0)
    key_phrases: list[str] = Field(max_length=5)
    summary: str = Field(max_length=200)

# 2. Convert to JSON Schema for the tool definition
tool_schema = {
    "name": "record_sentiment",
    "description": "Record the sentiment analysis result for a customer review.",
    "input_schema": {
        "type": "object",
        "properties": {
            "sentiment": {
                "type": "string",
                "enum": ["positive", "negative", "neutral", "mixed"],
                "description": "Overall sentiment of the review"
            },
            "confidence": {
                "type": "number",
                "minimum": 0.0,
                "maximum": 1.0,
                "description": "Confidence score from 0 to 1"
            },
            "key_phrases": {
                "type": "array",
                "items": {"type": "string"},
                "maxItems": 5,
                "description": "Up to 5 key phrases that drove the sentiment"
            },
            "summary": {
                "type": "string",
                "maxLength": 200,
                "description": "One-sentence summary of the sentiment reasoning"
            }
        },
        "required": ["sentiment", "confidence", "key_phrases", "summary"]
    }
}

client = anthropic.Anthropic()

def analyze_sentiment(review_text: str) -> SentimentResult:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        temperature=0,           # Maximise determinism
        tools=[tool_schema],
        tool_choice={"type": "any"},   # Force a tool call
        system=(
            "You are a sentiment analysis engine. "
            "Always call the record_sentiment tool with your analysis. "
            "Never respond with plain text."
        ),
        messages=[{
            "role": "user",
            "content": f"Analyze this customer review:\n\n{review_text}"
        }]
    )
    # The API guarantees a tool_use block when tool_choice=any
    tool_block = next(b for b in response.content if b.type == "tool_use")
    # Validate with Pydantic before returning
    return SentimentResult.model_validate(tool_block.input)

# Usage
review = "The delivery was shockingly fast but the product broke after two days. Support was helpful though."
result = analyze_sentiment(review)
print(result.model_dump_json(indent=2))
# Output is always valid JSON matching SentimentResult — no defensive parsing needed.

# WRONG: Silent failure on parse error
raw = response.content[0].text
try:
    result = json.loads(raw)
except json.JSONDecodeError:
    result = {}   # Silently returns empty dict — downstream sees missing fields

